type Fete = {
    prenom: string
    anecdote: string
}

export const fetes: Record<string, Fete> = {
    "01-01": { prenom: "Marie", anecdote: "Marie est l'un des prénoms les plus répandus au monde. En France, il a été porté par des reines, des actrices et même... des cyclones ! 👑" },
    "01-02": { prenom: "Basile", anecdote: "Saint Basile est le 'Père Noël' de la Grèce ! Les enfants grecs reçoivent leurs cadeaux le 1er janvier, jour de la Saint-Basile. 🎅" },
    "01-03": { prenom: "Geneviève", anecdote: "Sainte Geneviève est la patronne de Paris. La légende dit qu'elle aurait sauvé la ville d'Attila en 451 rien qu'avec ses prières. 🗼" },
    "01-04": { prenom: "Odilon", anecdote: "Odilon est un prénom rare qui vient du germanique 'od' (richesse). Il n'y a aujourd'hui que quelques centaines d'Odilon en France. 💎" },
    "01-05": { prenom: "Édouard", anecdote: "Édouard est un prénom royal par excellence : 8 rois d'Angleterre l'ont porté ! En France, il fut popularisé au XIXe siècle. 👑" },
    "01-06": { prenom: "Melchior", anecdote: "Melchior est l'un des Rois Mages ! Selon la tradition, il aurait apporté l'or à Jésus. C'est aussi le jour de l'Épiphanie et des galettes des rois 🫅" },
    "01-07": { prenom: "Raymond", anecdote: "Raymond vient du germanique 'ragin' (conseil) et 'mund' (protection). Raymond Poincaré, président de la République, l'a rendu célèbre en politique. 🏛️" },
    "01-08": { prenom: "Lucien", anecdote: "Lucien vient du latin 'lux' (lumière). C'est aussi le prénom du peintre Lucien Freud, petit-fils de Sigmund Freud ! 🎨" },
    "01-09": { prenom: "Alix", anecdote: "Alix est la forme médiévale d'Alice, rendue célèbre par Lewis Carroll. En France, c'est un prénom mixte porté depuis le Moyen Âge. 🐇" },
    "01-10": { prenom: "Guillaume", anecdote: "Plus de 30 saints portent ce prénom ! Guillaume Tell, Guillaume le Conquérant... ce prénom a vraiment marqué l'Histoire. 🏹" },
    "01-11": { prenom: "Paulin", anecdote: "Saint Paulin de Nole aurait inventé les cloches d'église au IVe siècle. Chaque fois que vous entendez sonner les cloches, pensez à lui ! 🔔" },
    "01-12": { prenom: "Tatiana", anecdote: "En Russie, le 25 janvier est la grande fête des Tatiana — c'est aussi la fête des étudiants russes ! Un prénom qui fait danser l'âme slave. 🪆" },
    "01-13": { prenom: "Yvette", anecdote: "Yvette vient du breton 'iv' (if, l'arbre). L'if est un arbre millénaire symbole d'éternité. Pas mal pour un prénom ! 🌳" },
    "01-14": { prenom: "Nina", anecdote: "Nina est la forme slave de Anne. C'est aussi le nom d'un célèbre parfum de Nina Ricci créé en 1987. Et celui d'une des caravelles de Christophe Colomb ! ⛵" },
    "01-15": { prenom: "Rémi", anecdote: "Saint Rémi a baptisé Clovis en 498, faisant de la France la 'fille aînée de l'Église'. Ce petit geste a changé toute l'histoire de France ! ✝️" },
    "01-16": { prenom: "Marcel", anecdote: "Marcel Proust, Marcel Duchamp, Marcel Pagnol... Ce prénom a donné à la France ses plus grands artistes et écrivains ! 🖊️" },
    "01-17": { prenom: "Roseline", anecdote: "Sainte Roseline de Villeneuve aurait accompli de nombreux miracles. Ses yeux, conservés dans une châsse, seraient restés intacts après sa mort en 1329. 👁️" },
    "01-18": { prenom: "Prisca", anecdote: "Prisca est l'un des prénoms les plus rares du calendrier français. Si vous connaissez une Prisca, elle fait partie d'un club très exclusif ! 🌸" },
    "01-19": { prenom: "Marius", anecdote: "Marius est indissociable de Marseille grâce à la trilogie de Pagnol. Mais c'était aussi le nom d'un grand général romain qui réforma l'armée. ⚓" },
    "01-20": { prenom: "Sébastien", anecdote: "Saint Sébastien est représenté transpercé de flèches — et pourtant il survécut ! Il est devenu le patron des archers... et des athlètes. 🏹" },
    "01-21": { prenom: "Agnès", anecdote: "Sainte Agnès est la patronne des jeunes filles. En anglais, 'lamb' (agneau) donna son nom Agnes. Elle mourut à seulement 13 ans en refusant de se marier. 🐑" },
    "01-22": { prenom: "Vincent", anecdote: "La Saint-Vincent est la fête des vignerons ! 'À la Saint-Vincent, l'hiver perd ou reprend' dit le dicton. Van Gogh portait ce prénom. 🍷" },
    "01-23": { prenom: "Barnard", anecdote: "Bernard vient du germanique 'bern' (ours) et 'hard' (fort). L'ours fort — voilà un prénom qui ne manque pas de caractère ! 🐻" },
    "01-24": { prenom: "François de Sales", anecdote: "François de Sales est le patron des journalistes car il utilisait des tracts imprimés pour évangéliser. Le premier 'influenceur' de l'histoire ? 📰" },
    "01-25": { prenom: "Conv. de Paul", anecdote: "Saint Paul était le pire ennemi des chrétiens avant sa conversion fulgurante sur le chemin de Damas. Preuve qu'on peut toujours changer d'avis ! ⚡" },
    "01-26": { prenom: "Timothée", anecdote: "Timothée vient du grec 'timao' (honorer) et 'theos' (dieu). C'est le prénom du plus jeune évêque de l'histoire chrétienne, disciple de Saint Paul. 📜" },
    "01-27": { prenom: "Angèle", anecdote: "Angèle de Mérici fonda les Ursulines, la première congrégation de femmes non cloîtrées. Une vraie révolutionnaire au XVIe siècle ! 💪" },
    "01-28": { prenom: "Thomas d'Aquin", anecdote: "Thomas d'Aquin était surnommé 'le Bœuf muet' par ses camarades car il était grand et silencieux. Il devint pourtant le plus grand philosophe chrétien ! 📚" },
    "01-29": { prenom: "Gildas", anecdote: "Gildas est un prénom breton porté par un moine celte du VIe siècle. Il est si rare aujourd'hui qu'on compte moins de 3000 Gildas en France ! 🍀" },
    "01-30": { prenom: "Martine", anecdote: "Martine, la célèbre héroïne des livres pour enfants, a été créée en 1954. Elle a vendu plus de 100 millions d'exemplaires dans le monde ! 📖" },
    "01-31": { prenom: "Marcelle", anecdote: "Marcelle vient du latin 'Marcellus', diminutif de Marcus (dieu Mars). C'est un prénom qui porte en lui toute la force de la Rome antique. ⚔️" },
    "02-01": { prenom: "Ella", anecdote: "Ella est la forme courte d'Eleanor ou Isabella. Ella Fitzgerald, surnommée 'la Première Dame du Jazz', a révolutionné la musique du XXe siècle. 🎵" },
    "02-02": { prenom: "Présentation", anecdote: "Le 2 février est la Chandeleur ! Si la marmotte voit son ombre, 6 semaines d'hiver... et si vous réussissez votre crêpe en la faisant sauter, vous aurez de la chance toute l'année ! 🥞" },
    "02-03": { prenom: "Blaise", anecdote: "Saint Blaise est le patron des médecins ORL car il aurait sauvé un enfant qui s'étouffait avec une arête. La bénédiction de la gorge se fait encore en son honneur ! 🏥" },
    "02-04": { prenom: "Véronique", anecdote: "Sainte Véronique aurait essuyé le visage de Jésus, et son image se serait imprimée sur le tissu. C'est la première 'photo' de l'histoire ! 📸" },
    "02-05": { prenom: "Agathe", anecdote: "Sainte Agathe est la patronne des infirmières ET des pompiers. En Sicile, on mange des gâteaux en forme de sein en son honneur. Étonnant ! 🎂" },
    "02-06": { prenom: "Gaston", anecdote: "Gaston Lagaffe, créé par Franquin en 1957, a rendu ce prénom immortel. Le vrai Gaston vient du germanique 'gast' (hôte). 😴" },
    "02-07": { prenom: "Eugénie", anecdote: "Eugénie de Montijo fut la dernière impératrice des Français, épouse de Napoléon III. Elle lança la mode des crinolines qui fit fortune aux couturiers ! 👗" },
    "02-08": { prenom: "Jacqueline", anecdote: "Jacqueline Kennedy a révolutionné la mode mondiale depuis la Maison Blanche. La petite veste Chanel rose qu'elle portait le jour de l'assassinat de JFK est entrée dans l'Histoire. 💋" },
    "02-09": { prenom: "Apolline", anecdote: "Sainte Apolline est la patronne des dentistes car elle fut torturée en se faisant arracher les dents. Pensez à elle la prochaine fois chez votre dentiste ! 🦷" },
    "02-10": { prenom: "Arnaud", anecdote: "Arnaud vient du germanique 'arn' (aigle) et 'wald' (gouverner). Arnaud de Villeneuve était un médecin du XIIIe siècle qui prescrivait... du vin aromatisé ! 🦅" },
    "02-11": { prenom: "N.-D. de Lourdes", anecdote: "Lourdes reçoit 6 millions de pèlerins par an, ce qui en fait la 2e destination de pèlerinage chrétien mondial après Rome. Une petite ville de 15 000 habitants ! ✨" },
    "02-12": { prenom: "Félix", anecdote: "Félix vient du latin 'felix' (heureux, chanceux). Le chat Félix, créé en 1919, fut la première star de l'animation. Né avant Mickey Mouse ! 🐱" },
    "02-13": { prenom: "Béatrice", anecdote: "Béatrice fut la muse de Dante qui lui dédia la Divine Comédie. Ils se sont rencontrés à 9 ans et ne se sont parlé que deux fois... un amour platonique épique ! 📜" },
    "02-14": { prenom: "Valentin", anecdote: "Saint Valentin était un évêque qui mariait secrètement des soldats romains dont le mariage était interdit. Arrêté et décapité le 14 février 269, il est devenu le saint des amoureux ! ❤️" },
    "02-15": { prenom: "Claude", anecdote: "Claude est un prénom mixte venant de la famille romaine Claudia. Claude Monet, Claude Debussy, Claude François... Ce prénom a tout d'un artiste ! 🎨" },
    "02-16": { prenom: "Julienne", anecdote: "Julienne de Cornillon est à l'origine de la Fête-Dieu, instituée en 1246. Le potage julienne (légumes en julienne) porte le même nom mais n'a aucun lien avec elle ! 🥕" },
    "02-17": { prenom: "Alexis", anecdote: "Alexis vient du grec 'alexein' (défendre, protéger). Alexis de Tocqueville, philosophe français, analysa la démocratie américaine avec une pertinence bluffante pour l'époque. 🗽" },
    "02-18": { prenom: "Bernadette", anecdote: "Bernadette Soubirous, qui eut les apparitions de Lourdes, est aujourd'hui conservée incorruptible dans une châsse à Nevers. Son corps n'aurait pas vieilli depuis 1879. 🌸" },
    "02-19": { prenom: "Gabin", anecdote: "Jean Gabin, icône du cinéma français, s'appelait en réalité Jean-Alexis Moncorgé. Il choisit son nom de scène en hommage à son père... qui s'appelait Gabin ! 🎬" },
    "02-20": { prenom: "Aimée", anecdote: "Aimée vient du latin 'amare' (aimer). C'est le prénom qui exprime le mieux la douceur. Aimée de Coigny inspira le poème 'La Jeune Captive' d'André Chénier. 💕" },
    "02-21": { prenom: "Damien", anecdote: "Saint Damien et son frère Côme étaient médecins et soignaient gratuitement. Ils sont les patrons des médecins et pharmaciens. Précurseurs de la médecine gratuite ! 💊" },
    "02-22": { prenom: "Isabelle", anecdote: "Isabelle la Catholique finança le voyage de Christophe Colomb. Sans elle, la découverte de l'Amérique aurait peut-être attendu ! ⛵" },
    "02-23": { prenom: "Lazare", anecdote: "Lazare est célèbre pour avoir été ressuscité par Jésus après 4 jours. Son nom est devenu commun : un 'lazaret' est un lieu de quarantaine. 🏥" },
    "02-24": { prenom: "Modeste", anecdote: "Modeste est l'un des prénoms les plus rares de France. Moins de 500 personnes le portent aujourd'hui. Modestement rare ! 🌷" },
    "02-25": { prenom: "Roméo", anecdote: "Roméo, immortalisé par Shakespeare, vient de l'italien 'romeo' (pèlerin de Rome). Le vrai Roméo Montaigu aurait réellement existé à Vérone au XIVe siècle. 🌹" },
    "02-26": { prenom: "Nestor", anecdote: "Nestor était dans la mythologie grecque le plus sage des guerriers grecs. Aujourd'hui un 'nestor' désigne familièrement le doyen d'un groupe. 🦉" },
    "02-27": { prenom: "Honorine", anecdote: "Honorine est la patronne de Normandie dont les reliques sont à Graville-Sainte-Honorine. C'est aussi le nom d'une pêcheuse dans les films de Marcel Pagnol ! ⚓" },
    "02-28": { prenom: "Romain", anecdote: "Romain Gary est le seul écrivain à avoir remporté deux fois le Prix Goncourt... sous deux noms différents ! Un tour de passe-passe littéraire resté célèbre. 📚" },
    "02-29": { prenom: "Auguste", anecdote: "Naître un 29 février est rarissime : 1 chance sur 1461 ! Ces 'sauts de grenouille' ne fêtent officiellement leur anniversaire que tous les 4 ans. Sont-ils éternellement jeunes ? 🐸" },
    "03-01": { prenom: "Aubin", anecdote: "Saint Aubin est le patron d'Angers. En Bretagne, on dit que la Saint-Aubin annonce le printemps. 'À la Saint-Aubin, les jours ont bien allongé.' 🌱" },
    "03-02": { prenom: "Charles le Bon", anecdote: "Charles le Bon, comte de Flandre, fut assassiné dans une église en 1127. Il fut béatifié pour ses nombreuses œuvres de charité envers les pauvres. 🕊️" },
    "03-03": { prenom: "Guénolé", anecdote: "Guénolé est un prénom breton ultra-rare. Il fonda l'abbaye de Landévennec en Bretagne vers 485. Moins de 1000 Guénolé vivent en France aujourd'hui ! 🍀" },
    "03-04": { prenom: "Casimir", anecdote: "Casimir, roi de Pologne, est le saint patron de la Pologne et de la Lituanie. En France, il est surtout connu grâce à un célèbre personnage de télévision pour enfants ! 👑" },
    "03-05": { prenom: "Olive", anecdote: "L'olivier est l'un des arbres les plus vieux du monde. Certains oliviers en Méditerranée ont plus de 2000 ans ! Olive, le prénom, est aussi rare que beau. 🫒" },
    "03-06": { prenom: "Colette", anecdote: "Colette, l'écrivaine française, fut la première femme à avoir des funérailles nationales en France (1954). Elle écrivit Gigi et Claudine avec un talent... et beaucoup d'audace ! ✍️" },
    "03-07": { prenom: "Félicité", anecdote: "Félicité vient du latin 'felicitas' (bonheur, chance). Flaubert écrivit 'Un cœur simple' pour une servante prénommée Félicité. Un des plus beaux prénoms porte-bonheur ! 🍀" },
    "03-08": { prenom: "Jean de Dieu", anecdote: "Le 8 mars est la Journée internationale des droits des femmes, instaurée en 1977 par l'ONU. Jean de Dieu, lui, fondait des hôpitaux pour les pauvres au XVIe siècle. 💪" },
    "03-09": { prenom: "Françoise", anecdote: "Françoise Sagan publia 'Bonjour Tristesse' à 18 ans et devint mondialement célèbre du jour au lendemain. Elle dépensa sa fortune aussi vite qu'elle l'avait gagnée ! 🚗" },
    "03-10": { prenom: "Vivien", anecdote: "Vivien (ou Viviane) est la fée du lac dans la légende arthurienne, gardienne de l'épée Excalibur. Un prénom qui sent bon la magie celtique ! 🗡️" },
    "03-11": { prenom: "Rosine", anecdote: "Rosine est la forme féminine de Roch, prénom occitan. C'est aussi le prénom de l'héroïne du Barbier de Séville de Beaumarchais, toujours aussi malicieuse ! 🎭" },
    "03-12": { prenom: "Justine", anecdote: "Justine vient du latin 'justus' (juste). Justine Henin, quadruple championne de Roland-Garros, a prouvé qu'on peut être petite et dominer les géants ! 🎾" },
    "03-13": { prenom: "Rodrigue", anecdote: "Rodrigue est le vrai prénom du Cid, héros de Corneille ! 'Va, je ne te hais point' dit Chimène dans la pièce. Une des répliques les plus célèbres du théâtre français. ⚔️" },
    "03-14": { prenom: "Mathilde", anecdote: "Mathilde vient du germanique 'macht' (force) et 'hild' (combat). La reine Mathilde d'Angleterre commanda la célèbre tapisserie de Bayeux, véritable BD médiévale ! 🧵" },
    "03-15": { prenom: "Louise", anecdote: "Louise Michel, la 'Vierge rouge de la Commune', fut déportée en Nouvelle-Calédonie pour avoir défendu les insurgés. Elle y apprit la langue kanake et défendit les indigènes ! ✊" },
    "03-16": { prenom: "Bénédicte", anecdote: "Bénédicte vient du latin 'benedictus' (béni). La liqueur Bénédictine, créée par des moines, contient 27 plantes et herbes. Sa recette exacte reste un secret jalousement gardé ! 🍶" },
    "03-17": { prenom: "Patrick", anecdote: "Saint Patrick, patron de l'Irlande, n'était pas irlandais mais gallois ! Il fut capturé comme esclave en Irlande à 16 ans avant d'en devenir l'évangélisateur. 🍀" },
    "03-18": { prenom: "Cyrille", anecdote: "Saint Cyrille inventa l'alphabet cyrillique (russe, bulgare, serbe...) au IXe siècle. Ce moine créa un système d'écriture qui sert encore à 250 millions de personnes ! 🔤" },
    "03-19": { prenom: "Joseph", anecdote: "Joseph est le patron des travailleurs, des artisans et des pères de famille. C'est aussi le prénom de Staline, de Napoléon (second prénom) et de... Tintin's chien Milou en espagnol ! 🔨" },
    "03-20": { prenom: "Herbert", anecdote: "Herbert vient du germanique 'heri' (armée) et 'beraht' (brillant). Herbert George Wells, dit H.G. Wells, inventa la machine à remonter le temps en littérature ! ⏱️" },
    "03-21": { prenom: "Clémence", anecdote: "Le 21 mars est le premier jour du printemps ! Clémence vient du latin 'clementia' (douceur). Bach naquit un 21 mars, tout comme les Gémeaux qui approchent... 🌸" },
    "03-22": { prenom: "Léa", anecdote: "Léa était la sœur aînée de Rachel dans la Bible. En France, Léa fut le prénom féminin le plus donné dans les années 2000. Simple, doux, intemporel ! 🌼" },
    "03-23": { prenom: "Victorien", anecdote: "L'ère victorienne (1837-1901) doit son nom à la reine Victoria. Victorien Sardou, dramaturge français, écrivit 'La Tosca' dont Puccini fit un opéra mondialement connu. 🎭" },
    "03-24": { prenom: "Cath. de Suède", anecdote: "Catherine de Suède quitta son mari pour suivre sa mère en pèlerinage à Rome. Elle y resta 25 ans... Son mari attendit-il ? L'histoire ne le dit pas ! 🛐" },
    "03-25": { prenom: "Annonciation", anecdote: "L'Annonciation est le jour où l'ange Gabriel annonce à Marie qu'elle attend Jésus. En Angleterre, ce fut le premier jour de l'année jusqu'en 1752 ! 👼" },
    "03-26": { prenom: "Larissa", anecdote: "Larissa est une ville de Grèce et aussi le nom d'un personnage de Tchekhov. Ce prénom venu de Russie signifie 'citadelle' en grec. 🏛️" },
    "03-27": { prenom: "Habib", anecdote: "Habib signifie 'bien-aimé' en arabe. C'est l'un des prénoms les plus poétiques du calendrier ! Habib Bourguiba fut le père de la Tunisie moderne. 🌙" },
    "03-28": { prenom: "Gontran", anecdote: "Gontran est un prénom mérovingien quasi-disparu. Le roi Gontran de Bourgogne était connu pour sa bonté et sa générosité. Aujourd'hui moins de 200 Gontran en France ! 👑" },
    "03-29": { prenom: "Gwladys", anecdote: "Gwladys est la forme galloise de Claudia. C'est un prénom celtique rarissime, porté par une sainte galloise du Ve siècle qui choisit la vie érémitique. 🏔️" },
    "03-30": { prenom: "Amédée", anecdote: "Amédée Mozart... c'est le second prénom de Wolfgang ! Amadeus en latin, Amédée en français. Il signifie 'celui qui aime Dieu'. 🎼" },
    "03-31": { prenom: "Benjamin", anecdote: "Benjamin était le plus jeune fils de Jacob dans la Bible. C'est pourquoi on appelle encore 'benjamin' le plus jeune d'un groupe ! 👶" },
    "04-01": { prenom: "Hugues", anecdote: "Le 1er avril, le poisson d'avril ! Hugues Capet fonda la dynastie capétienne. Mais surtout : colle un poisson dans le dos de quelqu'un aujourd'hui ! 🐟" },
    "04-02": { prenom: "Sandrine", anecdote: "Sandrine est une forme provençale d'Alexandra. C'est l'un des prénoms emblématiques des années 70-80 en France. Nostalgie garantie ! 🕺" },
    "04-03": { prenom: "Richard", anecdote: "Richard Cœur de Lion passait si peu de temps en Angleterre qu'il ne parlait pratiquement pas anglais ! Il préférait ses terres françaises et ses croisades. 🦁" },
    "04-04": { prenom: "Isidore", anecdote: "Saint Isidore de Séville est le saint patron d'Internet ! Il fut désigné par le Vatican en 1997 car il avait compilé TOUTE la connaissance de son époque en une encyclopédie. 💻" },
    "04-05": { prenom: "Irène", anecdote: "Irène Joliot-Curie, fille de Marie Curie, gagna elle aussi le Prix Nobel de Chimie en 1935. La pomme ne tombe pas loin de l'arbre radioactif ! ⚗️" },
    "04-06": { prenom: "Marcellin", anecdote: "Les frères Maristes furent fondés par un Marcellin (Champagnat). Ils créèrent des écoles dans le monde entier. Aujourd'hui plus de 500 000 élèves leur sont confiés ! 📚" },
    "04-07": { prenom: "Jean-Baptiste de la Salle", anecdote: "Jean-Baptiste de la Salle inventa l'école telle qu'on la connaît : enseignement en français (pas latin), élèves groupés par âge, instituteurs formés. Un révolutionnaire de la pédagogie ! 🏫" },
    "04-08": { prenom: "Julie", anecdote: "Julie était une prénom aristocratique romain. La 'Julie' de Rousseau dans 'La Nouvelle Héloïse' fit pleurer toute l'Europe au XVIIIe siècle. Un bestseller de l'époque ! 📖" },
    "04-09": { prenom: "Gautier", anecdote: "Gautier (ou Walter) vient du germanique 'walt' (gouverner) et 'heri' (armée). Gautier de Coincy écrivit au XIIIe siècle les premières chansons à la Vierge en français ! 🎵" },
    "04-10": { prenom: "Fulbert", anecdote: "Fulbert de Chartres construisit la magnifique cathédrale de Chartres après l'incendie de 1020. Un bâtisseur visionnaire dont l'œuvre traverse les siècles ! ⛪" },
    "04-11": { prenom: "Stanislas", anecdote: "Stanislas Leszczynski, roi de Pologne déchu, reçut en consolation le duché de Lorraine. Il fit construire la sublime place Stanislas à Nancy, classée UNESCO. 🏛️" },
    "04-12": { prenom: "Jules", anecdote: "Jules César, Jules Verne, Jules Renard... Ce prénom a enfanté des visionnaires ! Et en argot, 'jules' désigne le petit ami. Toujours utile à savoir ! ⚡" },
    "04-13": { prenom: "Ida", anecdote: "Ida est un prénom nordique venant de la déesse germanique Idun, gardienne des pommes de jouvence. Court, puissant, et plein de mythologie ! 🍎" },
    "04-14": { prenom: "Maxime", anecdote: "Maxime vient du latin 'maximus' (le plus grand). Le Cirque Maxime à Rome pouvait accueillir 250 000 spectateurs — le plus grand stade jamais construit ! 🏟️" },
    "04-15": { prenom: "Paterne", anecdote: "Paterne est un prénom breton rarissime. Mais ce jour marque surtout la naissance de Léonard de Vinci en 1452 ! Le plus grand génie de l'Histoire est né un 15 avril. 🎨" },
    "04-16": { prenom: "Benoît-Joseph", anecdote: "Benoît-Joseph Labre vécut dans une extrême pauvreté volontaire, errant de sanctuaire en sanctuaire. Il mourut à Paris en 1783, vénéré par les pauvres de la capitale. 🚶" },
    "04-17": { prenom: "Anicet", anecdote: "Anicet est un prénom d'origine grecque signifiant 'invincible'. Moins de 500 Anicet vivent en France. Si vous en croisez un, félicitez-le pour sa rareté ! 🛡️" },
    "04-18": { prenom: "Parfait", anecdote: "S'appeler Parfait, quelle pression ! Ce prénom vient du latin 'perfectus'. Le parfait (en pâtisserie) fut inventé en 1894. Aucun rapport, mais c'est parfait ! 🍦" },
    "04-19": { prenom: "Emma", anecdote: "Emma est le prénom le plus donné en France depuis 2000 avec Léa ! Madame Bovary s'appelle Emma. Jane Austen en fit aussi une héroïne inoubliable. 📚" },
    "04-20": { prenom: "Odette", anecdote: "Odette est la princesse-cygne dans le Lac des Cygnes de Tchaïkovski. Marcel Proust en fit aussi un personnage inoubliable dans 'À la recherche du temps perdu'. 🦢" },
    "04-21": { prenom: "Anselme", anecdote: "Anselme de Cantorbéry formula la preuve ontologique de l'existence de Dieu : 'Dieu est ce dont on ne peut rien concevoir de plus grand.' Un argument qui fait encore débat ! 🧠" },
    "04-22": { prenom: "Alexandre", anecdote: "Alexandre le Grand avait fondé 70 villes appelées Alexandrie ! Il conquit un empire de 5 millions de km² avant ses 30 ans. Et il pleurait car il n'avait plus rien à conquérir. 🌍" },
    "04-23": { prenom: "Georges", anecdote: "Saint Georges et le dragon : il aurait sauvé une princesse en terrassant un dragon en Libye. En réalité Georges était un soldat romain martyrisé. Il est patron de l'Angleterre ! 🐉" },
    "04-24": { prenom: "Fidèle", anecdote: "Fidèle vient du latin 'fidelis' (loyal, fidèle). C'est aussi le nom d'un célèbre chien dans '101 Dalmatiens' de Disney ! La loyauté comme prénom, c'est touchant. 🐕" },
    "04-25": { prenom: "Marc", anecdote: "Saint Marc, évangéliste, est le patron de Venise. Son symbole est le lion ailé qu'on voit partout dans la Sérénissime. Ses reliques auraient été volées en Égypte en 828 ! 🦁" },
    "04-26": { prenom: "Alida", anecdote: "Alida est la forme néerlandaise d'Adèle. C'est un prénom rare et élégant. Alida Valli, star du cinéma italien des années 50, le porta avec classe ! 🎬" },
    "04-27": { prenom: "Zita", anecdote: "Zita est la patronne des servantes et cuisinières. Elle travaillait si vite qu'on disait que les anges l'aidaient ! C'est aussi le prénom de la dernière impératrice d'Autriche. 👼" },
    "04-28": { prenom: "Valérie", anecdote: "Valérie vient du latin 'valere' (être fort, en bonne santé). C'est le prénom emblématique des années 60-70. 'Valérie' de France Gall reste un tube intemporel ! 🎵" },
    "04-29": { prenom: "Catherine de Sienne", anecdote: "Catherine de Sienne convainquit le pape Grégoire XI de quitter Avignon pour retourner à Rome en 1377. Elle n'avait reçu aucune éducation formelle. Docteure de l'Église ! 📜" },
    "04-30": { prenom: "Robert", anecdote: "Robert vient du germanique 'hrod' (gloire) et 'beraht' (brillant). Robert Bruce libéra l'Écosse. Robert De Niro illumine Hollywood. La gloire brillante, c'est son destin ! ✨" },
    "05-01": { prenom: "Fête du travail", anecdote: "Le 1er mai commémore les martyrs de Chicago de 1886 qui réclamaient la journée de 8h. On offre du muguet car il porte bonheur. Cueillez-le avant 8h du matin pour qu'il soit efficace ! 🌸" },
    "05-02": { prenom: "Boris", anecdote: "Boris vient du slave 'boriti' (combattre). Boris Vian, génial touche-à-tout français, écrivit 'L'Écume des jours' en 10 jours. Il mourut à 39 ans, laissant une œuvre immense. 🎷" },
    "05-03": { prenom: "Phil. et Jacques", anecdote: "Philippe vient du grec 'philos' (ami) et 'hippos' (cheval) : 'ami des chevaux'. Philippe II de Macédoine était le père d'Alexandre le Grand. 🐴" },
    "05-04": { prenom: "Sylvain", anecdote: "Sylvain vient du latin 'silva' (forêt). Sylvanus était le dieu romain des forêts. Que la force soit avec vous... et avec toutes les forêts de la planète ! 🌲" },
    "05-05": { prenom: "Judith", anecdote: "Judith, héroïne biblique, décapita le général ennemi Holopherne pour sauver son peuple. Ce fait divers de l'Antiquité inspira des dizaines de peintres dont Klimt ! 🗡️" },
    "05-06": { prenom: "Prudence", anecdote: "Prudence est l'une des 4 vertus cardinales avec Justice, Force et Tempérance. Aristote la considérait comme la vertu des vertus. Rare et sage comme prénom ! 🦉" },
    "05-07": { prenom: "Gisèle", anecdote: "Gisèle vient du germanique 'gisel' (otage, gage de paix). Des familles royales s'échangeaient leurs enfants en gage de paix. Gisèle de Bavière fut la femme du roi de Hongrie. 🕊️" },
    "05-08": { prenom: "Victoire", anecdote: "Le 8 mai 1945, c'est la fin de la Seconde Guerre mondiale en Europe ! Victoire vient du latin 'victoria'. Nike, déesse grecque de la victoire, a donné son nom à la célèbre marque. 🏆" },
    "05-09": { prenom: "Pacôme", anecdote: "Pacôme inventa le monachisme communautaire au IVe siècle : des moines qui vivent ET travaillent ensemble. Il est le père spirituel de tous les monastères du monde ! 🏛️" },
    "05-10": { prenom: "Solange", anecdote: "Sainte Solange, bergère du Berry, aurait été décapitée pour avoir refusé d'épouser un noble. Sa tête, selon la légende, aurait continué à marcher après sa décapitation ! 🐑" },
    "05-11": { prenom: "Estelle", anecdote: "Estelle vient du latin 'stella' (étoile). Estelle est aussi le nom d'un asteroid découvert en 1879. Votre Estelle préférée a une étoile qui porte son nom ! ⭐" },
    "05-12": { prenom: "Achille", anecdote: "Le talon d'Achille ! Ce héros grec était invulnérable... sauf au talon par lequel sa mère le tenait quand elle le plongea dans le Styx. Son point faible est entré dans la langue ! 🏹" },
    "05-13": { prenom: "Rolande", anecdote: "Rolande est le féminin de Roland, le neveu de Charlemagne. La Chanson de Roland (XIe siècle) est le plus ancien poème épique français. Durendal, son épée, était magique ! ⚔️" },
    "05-14": { prenom: "Matthias", anecdote: "Matthias fut tiré au sort pour remplacer Judas parmi les apôtres. Premier élu par vote dans l'histoire du christianisme ! La démocratie chrétienne avant l'heure. 🗳️" },
    "05-15": { prenom: "Denise", anecdote: "Denise vient de Dionysos, dieu grec du vin et de la fête ! Denise Fabre fut la première femme à présenter le journal télévisé sur une grande chaîne française. 🍷" },
    "05-16": { prenom: "Honoré", anecdote: "Saint Honoré est le patron des boulangers et pâtissiers ! La célèbre rue Saint-Honoré à Paris et le gâteau Saint-Honoré lui doivent leurs noms. 🥐" },
    "05-17": { prenom: "Pascal", anecdote: "Blaise Pascal inventa la première calculatrice mécanique à 19 ans pour aider son père percepteur ! Il donna aussi son nom à un langage informatique et à une unité de pression. 🖩" },
    "05-18": { prenom: "Éric", anecdote: "Éric le Rouge découvrit le Groenland vers 985 et lui donna ce nom trompeur (Pays Vert) pour attirer des colons. Son fils Leif Erikson atteignit l'Amérique 500 ans avant Colomb ! 🌊" },
    "05-19": { prenom: "Yves", anecdote: "Saint Yves est le patron des avocats et des Bretons. 'Saint Yves est breton, avocat et non larron, chose rare' disait-on au Moyen Âge. La corruption existait déjà ! ⚖️" },
    "05-20": { prenom: "Bernardin", anecdote: "Bernardin de Sienne inventait des slogans religieux et les imprimait sur des plaques de bois pour les diffuser. Le premier 'community manager' de l'histoire ! 📢" },
    "05-21": { prenom: "Constantin", anecdote: "Constantin le Grand légalisa le christianisme en 313 avec l'Édit de Milan. Il fit construire Constantinople (Istanbul) et baptisa l'Empire romain... à la toute fin de sa vie ! 🏛️" },
    "05-22": { prenom: "Émile", anecdote: "Émile Zola lança 'J'accuse !' dans l'affaire Dreyfus en 1898, risquant sa vie pour défendre la vérité. Un romancier qui s'engagea pour la justice. ✊" },
    "05-23": { prenom: "Didier", anecdote: "Didier vient du latin 'desiderium' (désir, nostalgie). Didier Deschamps est le seul joueur à avoir remporté la Coupe du monde à la fois comme joueur ET comme entraîneur. 🏆" },
    "05-24": { prenom: "Donatien", anecdote: "Le marquis de Sade s'appelait Donatien. Par pudeur, ses parents lui donnèrent ce prénom plutôt qu'un autre. Ce fut peut-être leur seule pudeur ! 📚" },
    "05-25": { prenom: "Sophie", anecdote: "Sophie vient du grec 'sophia' (sagesse). Sainte Sophie est vénérée en Orient. La basilique Sainte-Sophie d'Istanbul est l'un des plus beaux édifices du monde ! 🕌" },
    "05-26": { prenom: "Bérenger", anecdote: "Bérenger est un prénom médiéval venant du germanique 'bern' (ours) et 'ger' (lance). Un nom de guerrier qui porte la marque des grands conquérants ! 🐻" },
    "05-27": { prenom: "Augustin", anecdote: "Saint Augustin avoua dans ses Confessions avoir prié : 'Seigneur, rendez-moi chaste... mais pas encore !' L'honnêteté désarmante d'un futur saint ! 📖" },
    "05-28": { prenom: "Germain", anecdote: "Saint-Germain-des-Prés à Paris doit son nom à Germain, évêque de Paris au VIe siècle. Le quartier branché d'aujourd'hui s'appelait autrefois 'le pré de Saint-Germain'. 🎨" },
    "05-29": { prenom: "Aymar", anecdote: "Aymar de Nicolay, grand maître de Malte, résista aux Ottomans en 1565. L'ordre de Malte existe encore aujourd'hui et reste le plus petit État du monde ! 🛡️" },
    "05-30": { prenom: "Ferdinand", anecdote: "Magellan (Fernando de Magalhães) tenta le premier tour du monde mais mourut aux Philippines. Son équipage finit sans lui. Premier tour du monde : 1519-1522. 🌍" },
    "05-31": { prenom: "Visitation", anecdote: "La Visitation célèbre la rencontre de Marie et Élisabeth, qui portaient toutes deux un enfant miraculeux. C'est l'une des scènes les plus peintes de l'histoire de l'art ! 🎨" },
    "06-01": { prenom: "Justin", anecdote: "Justin vient du latin 'justus' (juste). Justin Bieber a commencé sa carrière à 13 ans grâce à YouTube. Du talent + les bons outils = une star planétaire ! 🎵" },
    "06-02": { prenom: "Blandine", anecdote: "Blandine de Lyon fut martyrisée en 177 dans l'amphithéâtre de Lyon devant des milliers de spectateurs. Elle est la première martyre française connue. 🦁" },
    "06-03": { prenom: "Kévin", anecdote: "Kevin (ou Caoimhín en irlandais) était un moine irlandais du VIe siècle qui vivait avec les animaux. C'est aussi le prénom le plus associé aux années 90 en France ! 🇮🇪" },
    "06-04": { prenom: "Clotilde", anecdote: "Clotilde, reine des Francs, convainquit Clovis de se convertir au christianisme. Sans elle, la France aurait peut-être été arienne ou même nordique. L'histoire tient à peu ! 👑" },
    "06-05": { prenom: "Igor", anecdote: "Igor Stravinsky composa 'Le Sacre du Printemps' en 1913. Sa première fut si scandaleuse que des bagarres éclatèrent dans la salle de l'Opéra de Paris ! 🎼" },
    "06-06": { prenom: "Norbert", anecdote: "Norbert vient du germanique 'nord' (nord) et 'beraht' (brillant). Norbert Wiener inventa la cybernétique en 1948, jetant les bases de l'informatique et de la robotique. 🤖" },
    "06-07": { prenom: "Gilbert", anecdote: "Gilbert vient du germanique 'gil' (gage) et 'beraht' (brillant). C'est aussi le nom d'un des cyclones les plus puissants jamais enregistrés dans l'Atlantique (1988) ! 🌀" },
    "06-08": { prenom: "Médard", anecdote: "Saint Médard est le saint de la pluie ! 'S'il pleut à la Saint-Médard, il pleut 40 jours plus tard.' Météorologiste avant l'heure ou simple légende ? ☔" },
    "06-09": { prenom: "Diane", anecdote: "Diane est la déesse romaine de la chasse et de la lune. Son temple à Éphèse était l'une des 7 merveilles du monde antique. Diana Spencer, princesse de Galles, porta ce prénom avec grâce. 🌙" },
    "06-10": { prenom: "Landry", anecdote: "Saint Landry fonda le premier Hôtel-Dieu de Paris vers 651 — le premier hôpital de la capitale, qui fonctionne encore aujourd'hui après 13 siècles ! 🏥" },
    "06-11": { prenom: "Barnabé", anecdote: "Barnabé était le plus grand des apôtres selon les chroniqueurs. Son prénom vient de l'araméen 'bar-naba' (fils de la consolation). Un consolateur d'exception ! 🤝" },
    "06-12": { prenom: "Guy", anecdote: "Guy de Maupassant détestait la Tour Eiffel mais déjeunait tous les jours dans son restaurant... parce que c'était le seul endroit de Paris d'où on ne la voyait pas ! 🗼" },
    "06-13": { prenom: "Antoine de Padoue", anecdote: "Antoine de Padoue est le saint le plus populaire après la Vierge ! Il est invoqué pour retrouver les objets perdus. Perdez votre téléphone ? Priez saint Antoine ! 📱" },
    "06-14": { prenom: "Élisée", anecdote: "Élisée Reclus, géographe anarchiste français du XIXe siècle, réalisa une Nouvelle Géographie universelle en 19 volumes. Il refusait tout honneur officiel. 🗺️" },
    "06-15": { prenom: "Germaine", anecdote: "Germaine Cousin, bergère pauvre et mal-aimée, partageait son peu de pain avec les miséreux. Sa charité était si grande qu'elle fut canonisée 150 ans après sa mort. 🐑" },
    "06-16": { prenom: "Jean-François Régis", anecdote: "Jean-François Régis parcourait les Cévennes à pied en hiver pour évangéliser. Il aidait aussi les femmes à sortir de la prostitution en leur trouvant du travail. 🚶" },
    "06-17": { prenom: "Hervé", anecdote: "Hervé est un prénom breton venant de 'haer' (bataille) et 've' (active). Saint Hervé était aveugle et se déplaçait guidé par un loup. Un saint qui apprivoisa les loups ! 🐺" },
    "06-18": { prenom: "Léonce", anecdote: "Le 18 juin 1940, De Gaulle lança son appel mythique depuis Londres. Léonce vient du grec 'leon' (lion). Ce jour est celui où un lion rugit pour ne jamais capituler ! 🦁" },
    "06-19": { prenom: "Romuald", anecdote: "Romuald fonda l'ordre des Camaldules où les moines vivaient en ermites totalement isolés. Il mourut seul dans sa cellule à 120 ans... selon la légende ! 🌲" },
    "06-20": { prenom: "Silvère", anecdote: "Le pape Silvère fut exilé par l'impératrice Théodora qui voulait imposer son propre pape. Déposé, il mourut de faim dans son île d'exil. La politique vaticane a toujours été féroce ! 🏝️" },
    "06-21": { prenom: "Rodolphe", anecdote: "Le 21 juin est le solstice d'été, le jour le plus long de l'année ! Rodolphe de Habsbourg fonda la dynastie qui régna sur l'Autriche jusqu'en 1918. ☀️" },
    "06-22": { prenom: "Alban", anecdote: "Saint Alban est le premier martyr d'Angleterre. Il donna sa vie pour protéger un prêtre chrétien. La ville de Saint Albans lui doit son nom. 🇬🇧" },
    "06-23": { prenom: "Audrey", anecdote: "Audrey Hepburn, icône de style, porta ce prénom saxon qui signifie 'noble force'. Elle travailla pour l'UNICEF les dernières années de sa vie, visitant des zones de famine. 💫" },
    "06-24": { prenom: "Jean-Baptiste", anecdote: "La Saint-Jean est célébrée avec des feux de joie dans toute l'Europe — tradition qui remonte aux fêtes celtes du solstice. Dans certaines régions, on saute par-dessus le feu pour se purifier ! 🔥" },
    "06-25": { prenom: "Prosper", anecdote: "Prosper vient du latin 'prosperus' (favorable, qui porte chance). C'est la devise de Seattle ! Prosper Mérimée écrivit Carmen, dont Bizet fit le plus célèbre opéra français. 🌹" },
    "06-26": { prenom: "Anthelme", anecdote: "Anthelme, évêque de Belley, refusa catégoriquement d'annuler le mariage du roi de France. Il tint bon malgré les pressions. Un homme d'une intégrité absolue ! 💪" },
    "06-27": { prenom: "Fernand", anecdote: "Fernand vient du germanique 'frith' (paix) et 'nand' (audacieux). Fernand Léger peignait des machines et des ouvriers avec autant d'amour qu'on peint des fleurs. 🎨" },
    "06-28": { prenom: "Irénée", anecdote: "Irénée de Lyon écrivit au IIe siècle le premier grand traité de théologie chrétienne. Il réfutait 'toutes les hérésies' — un défi qui occupait beaucoup de monde à l'époque ! 📜" },
    "06-29": { prenom: "Pierre et Paul", anecdote: "Pierre et Paul sont les deux colonnes de l'Église catholique. Ils furent exécutés le même jour à Rome. Pierre était pêcheur, Paul était intellectuel. Deux caractères opposés, une même foi ! ✝️" },
    "06-30": { prenom: "Martial", anecdote: "Martial vient du latin 'martialis' (de Mars, dieu de la guerre). Le poète Martial écrivit 1500 épigrammes cinglantes sur ses contemporains. Le premier 'twittos' de l'histoire ! 🏹" },
    "07-01": { prenom: "Thierry", anecdote: "Thierry vient du germanique 'theod' (peuple) et 'ric' (roi). Thierry La Fronde et Thierry Henry ont rendu ce prénom populaire dans des genres très différents ! ⚽" },
    "07-02": { prenom: "Martinien", anecdote: "Martinien était gardien de prison à Rome. Converti par un prisonnier chrétien, il libéra ses prisonniers et fut à son tour martyrisé. L'arroseur arrosé ! ⛓️" },
    "07-03": { prenom: "Thomas", anecdote: "Thomas 'l'incrédule' ne crut à la Résurrection qu'en touchant les plaies du Christ. Depuis, un 'Thomas' désigne quelqu'un qui doute de tout. Sommes-nous tous un peu Thomas ? 🤔" },
    "07-04": { prenom: "Florent", anecdote: "Le 4 juillet 1776, l'Indépendance américaine est signée ! La France y contribua grandement : sans Lafayette et Rochambeau, les États-Unis auraient peut-être perdu. 🗽" },
    "07-05": { prenom: "Antoine", anecdote: "Antoine de Saint-Exupéry écrivit Le Petit Prince, le livre français le plus traduit au monde (300 langues !). Il disparut en mission de reconnaissance en 1944. 🌹" },
    "07-06": { prenom: "Mariette", anecdote: "Auguste Mariette, égyptologue français, découvrit le Sérapéum de Memphis et fonda le musée du Caire. Il dormait parmi les momies... pour les protéger des pilleurs ! 🏺" },
    "07-07": { prenom: "Raoul", anecdote: "Raoul vient du germanique 'rad' (conseil) et 'ulf' (loup). Raoul Dufy peignait des régates et des courses de chevaux avec une joie de vivre éclatante. 🎨" },
    "07-08": { prenom: "Thibaut", anecdote: "Thibaut de Champagne était à la fois comte, roi de Navarre et... troubadour ! Ses chansons d'amour pour la reine Blanche de Castille sont encore chantées aujourd'hui. 🎵" },
    "07-09": { prenom: "Amandine", anecdote: "Amandine vient du latin 'amandus' (digne d'être aimé). C'est aussi le prénom de la première Française à avoir gravi l'Everest en 2003 : Amandine Havet. 🏔️" },
    "07-10": { prenom: "Ulrich", anecdote: "Ulrich est un prénom germanique venant de 'uodal' (patrimoine) et 'ric' (puissant). Il fut le premier saint canonisé officiellement par un pape, en 993. Un record historique ! 👑" },
    "07-11": { prenom: "Benoît", anecdote: "Saint Benoît fonda le Mont-Cassin et rédigea la Règle bénédictine : 'Ora et Labora' (Prie et Travaille). 1500 ans plus tard, ses moines font encore du fromage et de la bière ! 🍺" },
    "07-12": { prenom: "Olivier", anecdote: "Olivier Roland, compagnon de Roland dans La Chanson de Roland, était connu pour sa sagesse face à l'impétuosité de Roland. 'La valeur n'attend pas le nombre des années !' ⚔️" },
    "07-13": { prenom: "Henri et Joël", anecdote: "Henri vient du germanique 'heim' (maison) et 'ric' (roi). 8 rois de France s'appelèrent Henri ! Henri IV, 'le Vert Galant', promettait une poule au pot pour chaque Français. 🐔" },
    "07-14": { prenom: "Fête Nationale", anecdote: "Le 14 juillet 1789, la Bastille est prise ! En réalité, la forteresse ne contenait que 7 prisonniers ce jour-là. Mais le symbole valait bien une révolution ! 🎆" },
    "07-15": { prenom: "Donald", anecdote: "Donald vient du gaélique 'domhnall' (chef du monde). Donald Duck fut créé en 1934 et parle 5 langues dans les adaptations : français, allemand, suédois, finnois et anglais ! 🦆" },
    "07-16": { prenom: "N.-D. du Carmel", anecdote: "Le Mont Carmel, en Israël, est l'un des lieux saints les plus anciens du monothéisme. Le mot 'carmin' (rouge profond) vient du même mot sémitique que Carmel ! 🌄" },
    "07-17": { prenom: "Charlotte", anecdote: "Charlotte Corday assassina Marat dans son bain en 1793, convaincue de sauver la France. Elle monta à l'échafaud avec calme à 24 ans. David en fit un tableau mythique. 🗡️" },
    "07-18": { prenom: "Frédéric", anecdote: "Frédéric Chopin composait des nocturnes si tristes qu'ils faisaient pleurer tout Paris. Il était si pâle et fragile qu'on disait qu'il jouait avec ses dernières forces. 🎹" },
    "07-19": { prenom: "Arsène", anecdote: "Arsène Lupin, gentleman-cambrioleur créé par Maurice Leblanc, est le personnage de fiction français le plus populaire au Japon ! Il y a plus de 10 millions de lecteurs. 🎩" },
    "07-20": { prenom: "Marina", anecdote: "Le 20 juillet 1969, Apollo 11 se pose sur la Lune ! 'Un petit pas pour l'homme, un grand pas pour l'humanité.' Marina vient du latin 'marinus' (de la mer). 🌕" },
    "07-21": { prenom: "Victor", anecdote: "Victor Hugo écrivit Les Misérables en 17 ans d'exil. Il est l'auteur français le plus traduit dans le monde. Sa barbe blanche est aussi célèbre que ses œuvres ! 📚" },
    "07-22": { prenom: "Marie-Madeleine", anecdote: "Marie-Madeleine serait la première personne à avoir vu Jésus ressuscité. Elle termina sa vie en Provence, dans une grotte de la Sainte-Baume, en ermite. 🌿" },
    "07-23": { prenom: "Brigitte", anecdote: "Brigitte Bardot, sex-symbol mondial des années 60, vit depuis 1962 à Saint-Tropez qu'elle a... rendu célèbre. Elle se consacre aujourd'hui à la protection animale. 🐾" },
    "07-24": { prenom: "Christine", anecdote: "Christine de Pisan, née en 1364, est la première femme de lettres professionnelle française. Elle écrivait pour vivre, seule avec ses enfants. Pionnière absolue ! ✍️" },
    "07-25": { prenom: "Jacques", anecdote: "Saint Jacques est le patron de l'Espagne et des pèlerins. Le chemin de Compostelle attire chaque année 300 000 marcheurs. 'Buen Camino !' 🚶" },
    "07-26": { prenom: "Anne et Joachim", anecdote: "Anne et Joachim sont les grands-parents de Jésus, selon la tradition. Sainte Anne est particulièrement vénérée en Bretagne. Le pardon de Sainte-Anne d'Auray est le plus grand de Bretagne ! 🙏" },
    "07-27": { prenom: "Nathalie", anecdote: "Nathalie vient du latin 'natalis' (jour de naissance, Noël). C'est pour ça que Nathalie et Noël partagent la même racine ! 'Nathalie' de Gilbert Bécaud reste un tube des années 60. 🎵" },
    "07-28": { prenom: "Samson", anecdote: "Samson, dont la force résidait dans sa chevelure, fut trahi par Dalila qui le fit couper. Ses cheveux repoussèrent en prison, lui permettant de détruire le temple de ses ennemis ! 💪" },
    "07-29": { prenom: "Marthe", anecdote: "Marthe et Marie sont les deux sœurs de Lazare. Marthe s'affairait à la cuisine tandis que Marie écoutait Jésus. Ce contraste a donné 'vie active vs vie contemplative' en philosophie ! 🍳" },
    "07-30": { prenom: "Juliette", anecdote: "Roméo et Juliette : la plus célèbre histoire d'amour du monde ! Shakespeare la situe à Vérone où existe encore aujourd'hui le 'balcon de Juliette' visité par des millions de touristes. 🌹" },
    "07-31": { prenom: "Ignace de Loyola", anecdote: "Ignace de Loyola fonda la Compagnie de Jésus (les Jésuites) après avoir été blessé à la guerre. Les Jésuites créèrent les meilleures universités du monde... dont Sciences Po ! 🎓" },
    "08-01": { prenom: "Alphonse", anecdote: "Alphonse Daudet écrivit 'Les Lettres de mon moulin' dans un moulin provençal qui était en réalité celui de son ami. Il y allait juste pour... se reposer ! 🌾" },
    "08-02": { prenom: "Julien Eymard", anecdote: "Pierre-Julien Eymard vendit tous ses biens pour les pauvres. Ses supérieurs l'envoyèrent chez un psychiatre pour vérifier sa santé mentale. Le diagnostic : parfaitement sain ! 😄" },
    "08-03": { prenom: "Lydie", anecdote: "Lydie est un prénom venant de la Lydie, ancienne région de Turquie. Le roi Crésus régnait sur la Lydie et inventait la monnaie métallique. 'Riche comme Crésus' dit-on encore ! 💰" },
    "08-04": { prenom: "Jean-Marie Vianney", anecdote: "Le Curé d'Ars passait jusqu'à 16 heures par jour dans son confessionnal ! Des pèlerins venaient de toute l'Europe pour se confesser à lui. Il dormait 2 heures par nuit. 🙏" },
    "08-05": { prenom: "Abel", anecdote: "Abel est le premier meurtre de la Bible : tué par son frère Caïn par jalousie. En hébreu, Abel signifie 'souffle' ou 'vanité'. Niels Abel, mathématicien norvégien, mourut à 26 ans en laissant une œuvre révolutionnaire ! 🔢" },
    "08-06": { prenom: "Transfiguration", anecdote: "Le 6 août 1945, la bombe atomique est lâchée sur Hiroshima. Ce même jour, on célèbre la Transfiguration du Christ. L'humanité capable du pire comme du sublime. ☮️" },
    "08-07": { prenom: "Gaétan", anecdote: "Gaétan vient du latin 'Caietanus', habitant de Gaète en Italie. Gaétan Picon fut le directeur des Arts et Lettres qui protégea Malraux. Un prénom rare qui protège la culture ! 🎭" },
    "08-08": { prenom: "Dominique", anecdote: "Saint Dominique fonda l'ordre des Dominicains pour combattre l'hérésie par la prédication et non la force. Ses frères prêcheurs créèrent les premières universités médiévales ! 📚" },
    "08-09": { prenom: "Amour", anecdote: "S'appeler Amour, quel beau prénom ! Les Romains distinguaient différentes formes d'amour : Eros (passion), Philia (amitié), Storge (famille), Agape (amour universel). 💕" },
    "08-10": { prenom: "Laurent", anecdote: "Saint Laurent fut grillé sur un gril en fer. Selon la tradition, il aurait dit à ses bourreaux : 'Retournez-moi, je suis assez cuit d'un côté !' Un martyr avec de l'humour ! 🔥" },
    "08-11": { prenom: "Claire", anecdote: "Sainte Claire fonda les Clarisses, ordre féminin franciscain. Elle est la patronne de la télévision car, alitée, elle aurait vu et entendu une messe sur le mur de sa cellule ! 📺" },
    "08-12": { prenom: "Clarisse", anecdote: "Clarisse vient du latin 'clarus' (clair, brillant, célèbre). C'est un prénom lumineux porté par Clarisse Harlowe, héroïne du roman épistolaire le plus long jamais écrit (1748) ! ✨" },
    "08-13": { prenom: "Hippolyte", anecdote: "Hippolyte vient du grec 'hippos' (cheval) et 'lyo' (délier). Dans la mythologie, Hippolyte fut tué par ses propres chevaux affolés. Son prénom désigne aujourd'hui les épidémies hospitalières ! 🐴" },
    "08-14": { prenom: "Evrard", anecdote: "Evrard est un prénom germanique quasi-disparu. Moins de 200 Evrard en France ! Comme un trésor rare et précieux qui mérite d'être choyé. 💎" },
    "08-15": { prenom: "Assomption", anecdote: "Le 15 août est la fête nationale de l'Inde (indépendance en 1947), du Congo, de la Corée du Sud... et le jour de naissance de Napoléon Bonaparte (1769) ! 🌍" },
    "08-16": { prenom: "Armel", anecdote: "Armel est un prénom breton très rare. Il vient de 'art' (ours) et 'mael' (prince). Un prince ours breton : voilà un prénom qui a du panache ! 🐻" },
    "08-17": { prenom: "Hyacinthe", anecdote: "La fleur de jacinthe naquit selon la mythologie grecque du sang du jeune Hyakinthos, aimé d'Apollon et mort accidentellement. Une fleur née d'une tragédie d'amour ! 💐" },
    "08-18": { prenom: "Hélène", anecdote: "Hélène de Troie, 'le visage qui lança mille navires', déclencha la guerre de Troie. Hélène de Médicis devint Catherine de Médicis et introduisit... la fourchette en France ! 🍴" },
    "08-19": { prenom: "Jean-Eudes", anecdote: "Jean Eudes fut le premier à établir une fête liturgique du Cœur de Marie. Il parcourut la France pendant 50 ans pour prêcher et fonda des maisons pour les femmes en difficulté. 🙏" },
    "08-20": { prenom: "Bernard", anecdote: "Bernard de Clairvaux prêcha la 2e croisade avec tant d'éloquence que les gens découpaient ses vêtements pour en garder des morceaux. Le premier 'pop star' du Moyen Âge ! 🎤" },
    "08-21": { prenom: "Christophe", anecdote: "Saint Christophe, patron des voyageurs et automobilistes, portait les voyageurs sur son dos à travers un fleuve dangereux. Il fut retiré du calendrier officiel en 1969 ! 🚗" },
    "08-22": { prenom: "Fabrice", anecdote: "Fabrice vient du latin 'faber' (artisan, forgeron). Fabrice del Dongo est le héros de 'La Chartreuse de Parme' de Stendhal. Un prénom d'artisan pour un héros romanesque ! ⚒️" },
    "08-23": { prenom: "Rose de Lima", anecdote: "Rose de Lima se brûlait le visage avec du piment pour ne pas paraître belle. Première sainte des Amériques, canonisée en 1671. Lima (Pérou) porte son nom ! 🌹" },
    "08-24": { prenom: "Barthélémy", anecdote: "La Saint-Barthélémy (24 août 1572) : massacre de milliers de protestants à Paris. Les cloches de Saint-Germain l'Auxerrois sonnèrent le signal du massacre. L'histoire des dimanches n'est pas toujours paisible. ⛪" },
    "08-25": { prenom: "Louis", anecdote: "Louis IX (Saint Louis) rendait la justice sous un chêne à Vincennes, accessible à tous. Il est le seul roi de France canonisé. Paris lui doit le Sainte-Chapelle et la Sorbonne ! ⚜️" },
    "08-26": { prenom: "Natacha", anecdote: "Natacha vient du latin 'natalis' comme Noël et Nathalie. C'est le personnage le plus attachant de 'Guerre et Paix' de Tolstoï. Un prénom slave plein de chaleur ! ❄️" },
    "08-27": { prenom: "Monique", anecdote: "Monique est la mère de Saint Augustin. Elle pria pendant 17 ans pour la conversion de son fils libertin. Sa persévérance fut récompensée : Augustin devint Docteur de l'Église ! 🙏" },
    "08-28": { prenom: "Augustin", anecdote: "Saint Augustin est l'auteur des premières véritables Mémoires de l'histoire littéraire : ses 'Confessions' se lisent encore avec passion 1600 ans après ! 📚" },
    "08-29": { prenom: "Sabine", anecdote: "L'enlèvement des Sabines est l'un des fondements mythiques de Rome : Romulus fit enlever les femmes de la tribu voisine pour fonder une population. Un début de civilisation... particulier ! 🏛️" },
    "08-30": { prenom: "Fiacre", anecdote: "Saint Fiacre est le patron des jardiniers ET des chauffeurs de taxi ! Les premiers taxis parisiens (1630) stationnaient devant l'hôtel Saint-Fiacre, d'où le mot 'fiacre' ! 🚕" },
    "08-31": { prenom: "Aristide", anecdote: "Aristide Briand, 11 fois président du Conseil, reçut le Prix Nobel de la Paix en 1926. Il rêvait d'une Europe unie. Ses idées mirent 80 ans à se réaliser ! 🌍" },
    "09-01": { prenom: "Gilles", anecdote: "Saint Gilles est le patron des mendiants, handicapés et nourrices. Il vécut dans une grotte en Provence avec pour seule compagnie une biche. Un anachorète fascinant ! 🦌" },
    "09-02": { prenom: "Ingrid", anecdote: "Ingrid vient du vieux norrois 'Ing' (dieu de la fertilité) et 'fridr' (beauté). Ingrid Bergman remporta 3 Oscars et tourna avec Hitchcock, Rossellini et Casablanca. 🎬" },
    "09-03": { prenom: "Grégoire", anecdote: "Grégoire le Grand réorganisa la musique d'église au VIe siècle : le chant grégorien porte son nom ! Il envoya aussi des moines évangéliser l'Angleterre. Tout un programme ! 🎵" },
    "09-04": { prenom: "Rosalie", anecdote: "Rosalie vient du latin 'rosa' (rose). La Rosalie est aussi une tradition sicilienne de décorations de roses sur les tombes. Palerme célèbre sa sainte Rosalie avec faste ! 🌹" },
    "09-05": { prenom: "Raïssa", anecdote: "Raïssa Maritain, philosophe russe convertie au catholicisme, forma avec son mari Jacques l'un des couples intellectuels les plus brillants du XXe siècle. 🧠" },
    "09-06": { prenom: "Bertrand", anecdote: "Bertrand du Guesclin, connétable de France, était si laid qu'il dit un jour : 'Je suis si vilain que même ma mère ne m'aime pas.' Il libéra pourtant la France des Anglais ! ⚔️" },
    "09-07": { prenom: "Reine", anecdote: "Sainte Reine d'Alise fut martyrisée en refusant d'épouser un gouverneur romain. La source qui jaillit sur son tombeau est réputée guérir les maladies des yeux. 👁️" },
    "09-08": { prenom: "Nativité", anecdote: "Le 8 septembre célèbre la naissance de la Vierge Marie. C'est le jour que Richelieu choisit en 1642 pour inaugurer le Palais-Royal qu'il offrit au roi Louis XIII. 👶" },
    "09-09": { prenom: "Alain", anecdote: "Alain (le philosophe) écrivit 93 000 propos en 30 ans — un record ! Il affirmait écrire pour 'mâcher ses pensées'. Un intellectuel qui se nourrissait d'idées. 🧠" },
    "09-10": { prenom: "Inès", anecdote: "Inès de la Fressange, mannequin emblématique de Chanel, fut la première femme à prêter ses traits à Marianne sur les mairies françaises en 1989. 🇫🇷" },
    "09-11": { prenom: "Adelphe", anecdote: "Adelphe signifie 'frère' en grec. C'est l'un des prénoms les plus rares du calendrier. Et le 11 septembre rappelle que la fraternité internationale est plus nécessaire que jamais. 🕊️" },
    "09-12": { prenom: "Apollinaire", anecdote: "Guillaume Apollinaire inventa le mot 'surréalisme' ! Blessé pendant la guerre, il mourut de la grippe espagnole en 1918, 2 jours avant l'armistice. Si proche de la paix... 🎨" },
    "09-13": { prenom: "Aimé", anecdote: "Aimé Césaire, poète et homme politique martiniquais, inventa le concept de 'Négritude' et fut maire de Fort-de-France pendant 56 ans ! Politique ET poète : rarissime. ✊" },
    "09-14": { prenom: "La Sainte-Croix", anecdote: "Hélène, mère de Constantin, aurait retrouvé la vraie croix du Christ à Jérusalem en 326. Elle avait 75 ans quand elle entreprit ce pèlerinage. La curiosité n'a pas d'âge ! ✝️" },
    "09-15": { prenom: "Roland", anecdote: "Roland, neveu de Charlemagne, sonna si fort dans son cor à Roncevaux que ses tempes éclatèrent. Plutôt mourir que de demander de l'aide... un héros jusqu'au bout ! 📯" },
    "09-16": { prenom: "Edith", anecdote: "Édith Piaf, 'La Môme', née dans la misère, devint la chanteuse française la plus célèbre du monde. Elle disait : 'Je ne regrette rien'. Et c'était vrai. 🎤" },
    "09-17": { prenom: "Renaud", anecdote: "Renaud de Montauban, héros de chanson de geste médiévale, chevauchait le cheval magique Bayard qui grandissait pour porter 4 cavaliers. Les super-pouvoirs médiévaux ! 🐎" },
    "09-18": { prenom: "Nadège", anecdote: "Nadège vient du russe 'nadejda' (espoir). C'est un prénom slave qui s'est popularisé en France dans les années 80. L'espoir en prénom, quel beau programme ! 🌟" },
    "09-19": { prenom: "Émilie", anecdote: "Émilie du Châtelet, mathématicienne du XVIIIe siècle, traduisit et compléta Newton. Voltaire, son amant, disait qu'elle était 'un grand homme dont le seul défaut était d'être femme'. 🔭" },
    "09-20": { prenom: "Davy", anecdote: "Humphry Davy, chimiste anglais, inventa la lampe de sûreté pour les mineurs, sauvant des milliers de vies. Il est aussi le découvreur de plusieurs éléments chimiques. 💡" },
    "09-21": { prenom: "Matthieu", anecdote: "Matthieu était percepteur d'impôts (détesté de tous) quand Jésus l'appela. Caravage en fit un tableau époustouflant : la lumière divine frappant l'homme du fisc ! 💰" },
    "09-22": { prenom: "Maurice", anecdote: "Maurice Ravel composa le Boléro comme exercice d'orchestration... et en fit son œuvre la plus jouée au monde ! Il était gêné de son succès : 'Ce n'est qu'un long crescendo.' 🎼" },
    "09-23": { prenom: "Constance", anecdote: "Constance vient du latin 'constantia' (persévérance, fermeté). L'Édit de Constance (1183) est l'un des premiers actes de liberté de conscience de l'histoire. 🏛️" },
    "09-24": { prenom: "Thècle", anecdote: "Thècle aurait été disciple de Saint Paul au Ier siècle. Elle résista à tous les supplices : les lions refusèrent de la dévorer, le feu s'éteignit. Une résistante mythique ! 🦁" },
    "09-25": { prenom: "Hermann", anecdote: "Hermann le Clopeux, moine du XIe siècle, souffrait de terribles infirmités mais composa des hymnes magnifiques dont le Salve Regina. La souffrance sublimée en beauté. 🎵" },
    "09-26": { prenom: "Côme et Damien", anecdote: "Côme et Damien, frères médecins, auraient réalisé la première greffe de l'histoire : une jambe d'un homme mort sur un patient vivant. 1700 ans avant la transplantation moderne ! 🏥" },
    "09-27": { prenom: "Vinc. de Paul", anecdote: "Vincent de Paul créa les premières institutions sociales modernes : hospices, orphelinats, hôpitaux. Il est le patron de toutes les organisations caritatives catholiques. 🤝" },
    "09-28": { prenom: "Venceslas", anecdote: "Venceslas, duc de Bohème, fut assassiné par son frère jaloux en 935. Son manteau fut découpé et partagé entre des milliers de pèlerins. 'Good King Wenceslas' est encore chanté à Noël ! 🎄" },
    "09-29": { prenom: "Michel", anecdote: "L'archange Michel, chef des armées célestes, terrasse Satan représenté en dragon. Le Mont-Saint-Michel lui est dédié. 'Michaël' signifie 'Qui est comme Dieu ?' en hébreu. ⚔️" },
    "09-30": { prenom: "Jérôme", anecdote: "Jérôme traduisit la Bible en latin (la Vulgate) en 382. Il travaillait dans une grotte à Bethléem avec... un lion qu'il avait apprivoisé. On le représente toujours avec son lion ! 🦁" },
    "10-01": { prenom: "Thérèse", anecdote: "Thérèse de Lisieux mourut à 24 ans mais fut proclamée Docteure de l'Église. Sa 'petite voie' de confiance fut traduite en 60 langues. Elle voulait passer son paradis à faire du bien. 🌹" },
    "10-02": { prenom: "Léger", anecdote: "Léger vient du germanique 'leod' (peuple) et 'ger' (lance). Saint Léger, évêque d'Autun, eut les yeux crevés par ses ennemis politiques. La politique mérovingienne était brutale ! 👁️" },
    "10-03": { prenom: "Gérard", anecdote: "Gérard de Nerval se promenait dans les jardins du Palais-Royal avec un homard en laisse. Il expliquait : 'Il ne fait pas de bruit et connaît les mystères de la mer.' 🦞" },
    "10-04": { prenom: "François d'Assise", anecdote: "François d'Assise prêchait aux oiseaux et fit la paix avec un loup qui terrorisait une ville. Il est le patron des écologistes. Le pape François a choisi son nom en son honneur ! 🐦" },
    "10-05": { prenom: "Fleur", anecdote: "Fleur est un prénom poétique apparu au XIXe siècle avec le mouvement romantique. John Galsworthy créa le personnage de Fleur Forsyte, beauté impitoyable dans 'La Saga des Forsyte'. 🌺" },
    "10-06": { prenom: "Bruno", anecdote: "Bruno fonda l'ordre des Chartreux, des moines ermites qui ne se parlent presque jamais. Leurs abbayes sont parmi les plus silencieuses du monde. Silence absolu pendant 900 ans ! 🤫" },
    "10-07": { prenom: "Serge", anecdote: "Serge de Radonège, le plus grand saint de Russie, fondait des monastères dans les forêts. Les ours venaient manger dans sa main. Patron de Moscou et de toute la Russie ! 🐻" },
    "10-08": { prenom: "Pélagie", anecdote: "Pélagie d'Antioche était danseuse et pécheresse notoire avant de se convertir. Elle se déguisa en moine pour faire pénitence. Le travestissement au service de la sainteté ! 🎭" },
    "10-09": { prenom: "Denis", anecdote: "Saint Denis, premier évêque de Paris, fut décapité sur la butte Montmartre (Mont des Martyrs). Selon la légende, il ramassa sa tête et marcha 6 km jusqu'à sa sépulture ! 🗺️" },
    "10-10": { prenom: "Ghislain", anecdote: "Ghislain, ermite du VIIe siècle, fonda un monastère en Belgique. La ville de Saint-Ghislain lui doit son nom. Un prénom belge rare et attachant ! 🇧🇪" },
    "10-11": { prenom: "Firmin", anecdote: "Firmin, premier évêque d'Amiens, fut décapité. Sa tête devint une relique précieuse. La cathédrale d'Amiens lui est dédiée et abrite... un morceau de son crâne ! ⛪" },
    "10-12": { prenom: "Wilfrid", anecdote: "Le 12 octobre 1492, Christophe Colomb débarque en Amérique ! Wilfrid vient du germanique 'will' (volonté) et 'frid' (paix). La paix par la volonté... ou la découverte par l'obstination ! 🌎" },
    "10-13": { prenom: "Géraud", anecdote: "Géraud d'Aurillac était un comte qui rêvait d'être moine. Il se rasait secrètement la tonsure sous ses cheveux pour se sentir moine. Un noble candide et touchant ! ✂️" },
    "10-14": { prenom: "Juste", anecdote: "Juste vient du latin 'justus' (juste). Aristote définissait la justice comme 'donner à chacun ce qui lui revient'. Simple à dire, difficile à appliquer depuis 2400 ans ! ⚖️" },
    "10-15": { prenom: "Thérèse d'Avila", anecdote: "Thérèse d'Avila réforma l'ordre du Carmel à 47 ans et parcourut l'Espagne en charrette par tous les temps. Quand elle se plaignait à Dieu des épreuves, Il répondit : 'C'est comme ça que je traite mes amis.' Elle répliqua : 'C'est pour ça que vous en avez si peu !' 😄" },
    "10-16": { prenom: "Edwige", anecdote: "Edwige vient du germanique 'hadu' (combat) et 'wig' (guerre). Edwige Feuillère, grande dame du théâtre français, joua Phèdre pendant 30 ans sans jamais se lasser. 🎭" },
    "10-17": { prenom: "Baudouin", anecdote: "Baudouin IV de Jérusalem, 'le roi lépreux', défendit son royaume malgré sa maladie avec un courage extraordinaire. Il mourut à 24 ans après avoir régné avec grandeur. 👑" },
    "10-18": { prenom: "Luc", anecdote: "Saint Luc est le patron des peintres car il aurait peint le portrait de la Vierge. Ses Évangiles sont les plus littéraires. Il était médecin avant de suivre Paul. 🎨" },
    "10-19": { prenom: "René", anecdote: "René Descartes eut l'idée du cogito ('Je pense donc je suis') dans un rêve ! Il dormait 10 heures par nuit et ne commençait à travailler qu'en milieu de matinée. 🧠" },
    "10-20": { prenom: "Adeline", anecdote: "Adeline vient du germanique 'adal' (noble). Adeline d'Orvieto était tertiaire dominicaine et aurait lévité pendant la prière. Les témoins la virent flotter au-dessus du sol ! 🌬️" },
    "10-21": { prenom: "Céline", anecdote: "Céline Dion, québécoise élevée au rang de diva mondiale, est la chanteuse française la plus vendue de l'histoire avec 250 millions d'albums ! Elle a commencé à chanter à 5 ans. 🎵" },
    "10-22": { prenom: "Élodie", anecdote: "Élodie et sa sœur Nunilone furent martyrisées en Espagne en 851 pour leur foi chrétienne. Élodie vient de 'alodia' en wisigoth. Un prénom médiéval redécouvert au XXe siècle ! ✝️" },
    "10-23": { prenom: "Jean de Capistran", anecdote: "Jean de Capistran conduisit une armée de croisés à la victoire contre les Turcs à Belgrade en 1456 à l'âge de 70 ans ! Preuve qu'on peut être guerrier jusque dans sa vieillesse. ⚔️" },
    "10-24": { prenom: "Florentin", anecdote: "Florence (et Florentin) viennent du latin 'florens' (florissant, en fleurs). Florence Nightingale inventa les soins infirmiers modernes pendant la guerre de Crimée. 🏥" },
    "10-25": { prenom: "Crépin", anecdote: "Saint Crépin est le patron des cordonniers. La nuit, il volait du cuir aux riches pour faire des chaussures aux pauvres. Le Robin des Bois de la chaussure ! 👟" },
    "10-26": { prenom: "Dimitri", anecdote: "Dimitri vient du grec 'Déméter', déesse des moissons. Dimitri Chostakovitch composa sa 7e Symphonie pendant le siège de Leningrad. Elle fut diffusée par radio pour soutenir les résistants. 🎼" },
    "10-27": { prenom: "Émeline", anecdote: "Émeline est un prénom médiéval forme d'Ameline, venu du germanique. Très rare en France (moins de 3000), c'est un prénom à la sonorité délicate et précieuse. 🌸" },
    "10-28": { prenom: "Simon et Jude", anecdote: "Jude est le saint des causes désespérées — le saint qu'on prie quand tout va mal ! Son culte est énorme aux États-Unis. Il ne faut pas confondre avec Judas Iscariote... 🙏" },
    "10-29": { prenom: "Narcisse", anecdote: "Narcisse, dans la mythologie grecque, tomba amoureux de son reflet et se noya dans une fontaine. Il donna son nom au narcissisme. La fleur narcisse poussa sur l'endroit de sa mort. 🌼" },
    "10-30": { prenom: "Bienvenu", anecdote: "S'appeler Bienvenu, c'est porter le bonheur partout où on va ! Bienvenu de Gubbio, compagnon de François d'Assise, était connu pour sa joie contagieuse. Le bonheur comme prénom ! 😊" },
    "10-31": { prenom: "Quentin", anecdote: "Halloween ! Saint Quentin fut martyrisé et sa tête roula jusqu'à une source. La ville de Saint-Quentin porte son nom. En cette nuit des morts, pensez aussi aux saints ! 🎃" },
    "11-01": { prenom: "Toussaint", anecdote: "La Toussaint fut fixée au 1er novembre pour concurrencer les fêtes celtes de Samhain (Halloween). On fleurit les tombes... une tradition qui n'a que 150 ans en France ! 🌸" },
    "11-02": { prenom: "Défunts", anecdote: "Le Jour des Morts est fêté différemment selon les cultures : chrysanthèmes en France, marigolds et squelettes colorés au Mexique, offrandes en Asie. La mort unit l'humanité ! 💀" },
    "11-03": { prenom: "Hubert", anecdote: "Saint Hubert est le patron des chasseurs. Selon la légende, il chassa un cerf portant une croix lumineuse entre ses bois. Ce cerf le convertit ! L'animal le plus évangéliste de l'histoire. 🦌" },
    "11-04": { prenom: "Charles", anecdote: "Charles vient du germanique 'karl' (homme libre, fort). Charlemagne, Charles de Gaulle, Charles Aznavour, Prince Charles... Ce prénom porte des destins hors du commun ! 👑" },
    "11-05": { prenom: "Sylvie", anecdote: "Sylvie vient du latin 'silva' (forêt). La Sylvie de Nerval est une de ses plus belles nouvelles. Claude Sylvestre Bonnot dit Sylvie fut la première femme jockey en France ! 🌲" },
    "11-06": { prenom: "Bertille", anecdote: "Bertille fut abbesse de Chelles au VIIe siècle et dirigea une abbaye double (hommes ET femmes). Une femme à la tête d'une communauté mixte au Moyen Âge : révolutionnaire ! 👸" },
    "11-07": { prenom: "Carine", anecdote: "Carine vient de Karin, forme scandinave de Catherine. Marie Curie, née Manja, choisit Marie-Carine en France. La plus grande scientifique du monde aimait les prénoms français ! ⚗️" },
    "11-08": { prenom: "Geoffroy", anecdote: "Geoffroy de Villehardouin écrivit la première grande œuvre en prose française : la 'Conquête de Constantinople' (1213). Il inventa le journalisme d'histoire ! ✍️" },
    "11-09": { prenom: "Théodore", anecdote: "Le 9 novembre 1989, le mur de Berlin tombe ! Théodore vient du grec 'theos' (dieu) et 'doron' (don). Ce prénom de 'don de Dieu' coïncide avec une journée historique pour la liberté ! 🗽" },
    "11-10": { prenom: "Léon", anecdote: "Léon vient du latin 'leo' (lion). Léon Tolstoï écrivait debout ! Il marcha 20 000 km dans sa vie et mourut à 82 ans dans une petite gare de campagne en fuyant sa femme. 🦁" },
    "11-11": { prenom: "Armistice", anecdote: "Le 11 novembre 1918 à 11h, les cloches sonnèrent la fin de la Grande Guerre. 'La der des ders' disait-on. Hélas... Mais chaque 11 novembre, le monde s'arrête une minute pour se souvenir. 🕊️" },
    "11-12": { prenom: "Christian", anecdote: "Christian Dior révolutionna la mode en 1947 avec son 'New Look'. Les femmes portaient alors des jupes larges et cintrées après des années de restrictions. La liberté par la mode ! 👗" },
    "11-13": { prenom: "Brice", anecdote: "Brice de Tours succéda à Saint Martin. Accusé faussement, il marcha sur des charbons ardents pour prouver son innocence. 'Brice de Nice' de Philippe Lacheau n'a rien à voir ! 😄" },
    "11-14": { prenom: "Sidoine", anecdote: "Sidoine Apollinaire, évêque de Clermont au Ve siècle, est l'un des derniers Latins à avoir écrit avec l'élégance des grands classiques. Le crépuscule d'une civilisation. 🌅" },
    "11-15": { prenom: "Albert", anecdote: "Albert Einstein était tellement distrait qu'il utilisait son chèque Nobel comme marque-page et le perdit ! Il jouait du violon et disait que si la physique ne marchait pas, il serait musicien. 🎻" },
    "11-16": { prenom: "Marguerite", anecdote: "Marguerite Yourcenar fut la première femme élue à l'Académie française en 1980. Elle dut attendre 345 ans après la fondation de l'institution. L'immortalité mérite patience ! 📚" },
    "11-17": { prenom: "Élisabeth", anecdote: "Élisabeth vient de l'hébreu 'eli-sheba' (mon Dieu est plénitude). 3 reines d'Angleterre, 1 impératrice d'Autriche (Sissi)... Un prénom royal et solaire ! 👑" },
    "11-18": { prenom: "Aude", anecdote: "Aude est la fiancée de Roland dans la Chanson de Roland. Apprenant la mort de Roland, elle mourut de douleur. Ce fut le premier 'mort de chagrin' de la littérature française. 💔" },
    "11-19": { prenom: "Tanguy", anecdote: "Tanguy est un prénom breton venant de 'tan' (feu) et 'ki' (chien). Yves Tanguy, peintre surréaliste breton, créait des paysages lunaires d'une étrangeté absolue. 🎨" },
    "11-20": { prenom: "Edmond", anecdote: "Edmond Dantès, le Comte de Monte-Cristo, est le héros de vengeance le plus célèbre de la littérature ! Dumas l'écrivit en 1844. Sa devise : 'Attendre et espérer.' 🗡️" },
    "11-21": { prenom: "Prés. de Marie", anecdote: "La présentation de Marie au Temple : à 3 ans, elle aurait gravi seule les 15 marches du Temple de Jérusalem. Les anges l'auraient nourrie pendant ses années au Temple ! 👼" },
    "11-22": { prenom: "Cécile", anecdote: "Sainte Cécile est la patronne des musiciens car elle aurait chanté dans son cœur lors de son mariage forcé. L'Académie de Sainte-Cécile de Rome lui est dédiée. 🎵" },
    "11-23": { prenom: "Clément", anecdote: "Clément vient du latin 'clemens' (doux, bienveillant). Clément Ader fit décoller le premier aéroplane en 1890, 13 ans avant les frères Wright ! Les Français l'ont oublié... ✈️" },
    "11-24": { prenom: "Flora", anecdote: "Flora est la déesse romaine des fleurs et du printemps. Flora Tristan, grand-mère du peintre Gauguin, fut l'une des premières féministes socialistes françaises au XIXe siècle. 🌺" },
    "11-25": { prenom: "Catherine", anecdote: "La Sainte-Catherine était la fête des 'catherinettes' : les célibataires de 25 ans coiffaient Sainte Catherine (une statue) d'un chapeau loufoque. Une tradition disparue mais attachante ! 🎩" },
    "11-26": { prenom: "Delphine", anecdote: "Delphine vient de Delphes, lieu de l'oracle d'Apollon. Madame de Staël écrivit 'Delphine' en 1802, premier roman épistolaire féministe français. Napoléon le fit interdire ! 📚" },
    "11-27": { prenom: "Séverin", anecdote: "Le quartier Saint-Séverin à Paris (5e arr.) porte le nom d'un ermite du VIe siècle. Son église gothique flamboyant est l'une des plus belles de Paris ! ⛪" },
    "11-28": { prenom: "Jacques de la Marche", anecdote: "Jacques de la Marche parcourut toute l'Europe à pied pour prêcher. On estime qu'il marcha 150 000 km dans sa vie. Un record avant même l'invention du compteur ! 👟" },
    "11-29": { prenom: "Saturnin", anecdote: "Saint Saturnin, premier évêque de Toulouse, fut attaché à un taureau qui l'emporta dans les escaliers du Capitole. Les escaliers s'appelèrent 'degrés de Saturnin'. 🐂" },
    "11-30": { prenom: "André", anecdote: "Saint André est le patron de l'Écosse, de la Russie et de la Grèce ! Sa croix en X est sur le drapeau écossais. Frère de Simon-Pierre, il fut crucifié à Patras en Grèce. ✝️" },
    "12-01": { prenom: "Florence", anecdote: "Florence Nightingale, née à Florence, révolutionna les soins infirmiers en tenant des statistiques — elle inventa même le graphique circulaire pour convaincre le Parlement ! 📊" },
    "12-02": { prenom: "Viviane", anecdote: "Viviane, la fée du lac de la légende arthurienne, donna Excalibur à Arthur et enferma Merlin dans un arbre. Une femme puissante dans un monde d'épées ! 🗡️" },
    "12-03": { prenom: "François-Xavier", anecdote: "François Xavier, co-fondateur des Jésuites, évangélisa seul l'Inde, le Japon et la Chine. Il aurait baptisé 30 000 personnes. Un voyageur infatigable du XVIe siècle ! 🌏" },
    "12-04": { prenom: "Barbara", anecdote: "Sainte Barbe est la patronne des artificiers et pompiers car son père fut foudroyé en la décapitant. On la représente avec un canon ! La Barbe est aussi fêtée par les marins. 💣" },
    "12-05": { prenom: "Gérald", anecdote: "Gérald vient du germanique 'ger' (lance) et 'wald' (gouverner). Gérald de Aurillac vendit ses biens pour les pauvres et fonda une abbaye sur ses terres. Un seigneur généreux ! 🏰" },
    "12-06": { prenom: "Nicolas", anecdote: "Saint Nicolas, évêque de Myre, est le vrai Père Noël ! Il ressuscita 3 enfants tués par un boucher et dota secrètement des jeunes filles pauvres. Son culte est encore vivace en Alsace ! 🎅" },
    "12-07": { prenom: "Ambroise", anecdote: "Ambroise de Milan fut élu évêque par acclamation populaire alors qu'il n'était même pas baptisé ! Il dut être baptisé et ordonné prêtre en une semaine. Un parcours éclair ! ⚡" },
    "12-08": { prenom: "Immaculée Conception", anecdote: "Le 8 décembre, Lyon s'illumine depuis 1852 ! La Fête des Lumières attire chaque année 3 millions de visiteurs. Une des plus belles traditions françaises. ✨" },
    "12-09": { prenom: "Pierre Fourier", anecdote: "Pierre Fourier créa des écoles gratuites pour les filles pauvres en Lorraine au XVIIe siècle. L'éducation des femmes, radical pour l'époque. Il fut un pionnier absolu ! 📚" },
    "12-10": { prenom: "Romaric", anecdote: "Romaric, noble alsacien du VIIe siècle, abandonna sa fortune pour fonder un double monastère avec son ami Amé. Il donna tous ses serfs en liberté. Le premier abolitionniste alsacien ! 🕊️" },
    "12-11": { prenom: "Daniel", anecdote: "Daniel survécut à la fosse aux lions grâce à sa foi. Il interpréta aussi l'écriture mystérieuse sur le mur ('Mané Técel Pharès'). 'Lire l'écriture sur le mur' vient de là ! 🦁" },
    "12-12": { prenom: "Jeanne de Chantal", anecdote: "Jeanne de Chantal fonda la Visitation pour accueillir les femmes âgées ou malades que les autres ordres refusaient. Un ordre de l'inclusion avant l'heure ! 🤍" },
    "12-13": { prenom: "Lucie", anecdote: "Sainte Lucie est la fête de la lumière en Scandinavie ! Les jeunes filles portent des couronnes de bougies. En Suède, c'est l'une des fêtes les plus attendues de l'année. 🕯️" },
    "12-14": { prenom: "Odile", anecdote: "Sainte Odile, patronne d'Alsace, naquit aveugle et recouvra la vue lors de son baptême. Sa chapelle au Mont Sainte-Odile domine les vignes alsaciennes à 760m d'altitude. 🍇" },
    "12-15": { prenom: "Ninon", anecdote: "Ninon de Lenclos, courtisane et philosophe du XVIIe siècle, reçut dans son salon Molière, La Fontaine et Voltaire enfant ! Elle resta belle et spirituelle jusqu'à 85 ans. 💋" },
    "12-16": { prenom: "Alice", anecdote: "Alice au Pays des Merveilles fut écrit par Lewis Carroll pour une petite fille de 10 ans lors d'un pique-nique. Il inventa l'histoire pour la distraire... et créa un chef-d'œuvre ! 🐇" },
    "12-17": { prenom: "Gaël", anecdote: "Gaël vient du celtique 'gael' (généreux). C'est aussi le nom d'un peuple celtique qui donna son nom à la Galice espagnole et à la Gaule... et donc à la France ! 🍀" },
    "12-18": { prenom: "Gatien", anecdote: "Gatien, premier évêque de Tours, vécut si longtemps (mort à 120 ans selon la tradition) qu'il convertit la Touraine entière. La longévité au service de la foi ! 🏛️" },
    "12-19": { prenom: "Urbain", anecdote: "Urbain vient du latin 'urbanus' (citadin, poli). Urbain V est le seul pape béatifié du XIVe siècle. Le mot 'urbanité' (politesse) vient du même latin ! 🏙️" },
    "12-20": { prenom: "Abraham", anecdote: "Abraham est le père commun des trois religions monothéistes : judaïsme, christianisme, islam. Né à Ur en Mésopotamie, il est le premier à avoir cru en un Dieu unique. 🕊️" },
    "12-21": { prenom: "Pierre Canisius", anecdote: "Le 21 décembre est le solstice d'hiver, la nuit la plus longue ! Pierre Canisius écrivit le premier catéchisme illustré pour enfants. Les BD pédagogiques ont de vieilles racines ! 🌙" },
    "12-22": { prenom: "Françoise-Xavière", anecdote: "Françoise-Xavière Cabrini fut la première citoyenne américaine canonisée (1946). Immigrée italienne, elle créa 67 institutions pour les immigrants pauvres aux États-Unis. 🗽" },
    "12-23": { prenom: "Armand", anecdote: "Armand vient du germanique 'herman' (homme d'armée). Armand Jean du Plessis... c'est le vrai nom du Cardinal de Richelieu ! Le plus grand homme d'État français avait un prénom simple. 🃏" },
    "12-24": { prenom: "Réveillon", anecdote: "La nuit de Noël est célébrée par 2 milliards de personnes ! La tradition du sapin vient d'Alsace (XVe siècle). Celle des cadeaux vient de Saint Nicolas. Et la bûche ? Du solstice celtique ! 🎄" },
    "12-25": { prenom: "Noël", anecdote: "Joyeux Noël ! Le 25 décembre était la fête du Sol Invictus (Soleil Invaincu) dans la Rome antique. L'Église choisit cette date pour célébrer la 'Lumière du monde'. ✨🎅" },
    "12-26": { prenom: "Étienne", anecdote: "Étienne est le premier martyr chrétien, lapidé à Jérusalem vers 35 après JC. C'est pour ça que la Saint-Étienne est le lendemain de Noël. Stephen Hawking est né un 8 janvier. 💫" },
    "12-27": { prenom: "Jean", anecdote: "Jean est le prénom le plus donné à travers l'histoire en Occident ! 23 papes, des dizaines de rois, des milliers de saints... Jean vient de l'hébreu 'Yohanan' (Dieu est miséricordieux). 😇" },
    "12-28": { prenom: "Innocents", anecdote: "Les Saints Innocents rappellent les enfants massacrés par Hérode. En Espagne, ce jour est leur 1er avril ! Les farces et blagues du Día de los Santos Inocentes sont une tradition vivace. 😄" },
    "12-29": { prenom: "David", anecdote: "David vainquit Goliath avec une fronde... mais devint aussi poète, musicien et roi ! Les Psaumes lui sont attribués. David Bowie, David Beckham, David Copperfield... un prénom de légende ! 🎸" },
    "12-30": { prenom: "Roger", anecdote: "Roger vient du germanique 'hrod' (gloire) et 'ger' (lance). Roger Federer a remporté 20 tournois du Grand Chelem. Et Roger Rabbit a révolutionné l'animation en 1988 ! 🎾" },
    "12-31": { prenom: "Sylvestre", anecdote: "Le pape Sylvestre Ier baptisa Constantin le Grand selon la légende. La Saint-Sylvestre est le réveillon du Nouvel An ! On dit qu'embrasser quelqu'un à minuit porte bonheur toute l'année. 🥂" },
}

export function getFeteduJour(): Fete {
    const today = new Date()
    const month = String(today.getMonth() + 1).padStart(2, "0")
    const day = String(today.getDate()).padStart(2, "0")
    const key = `${month}-${day}`
    return fetes[key] ?? { prenom: "Fête du jour", anecdote: "Profitez de cette belle journée ! ☀️" }
}